import { api } from './client'
import type { SubscriptionDto } from './subscriptions'
import type { SlotDto } from './schedule'
import type { ReportDto } from './lessonReports'

export interface ChildSummaryDto {
  childId: string
  subscription: SubscriptionDto | null
  upcomingSlots: SlotDto[]
  recentReports: ReportDto[]
}

export function fetchChildSummary(childId: string): Promise<ChildSummaryDto> {
  return api.get<ChildSummaryDto>(`/parent/children/${childId}/summary`)
}
