import { useEffect, useState } from 'react'
import { Link } from 'react-router-dom'
import PlatformShell from '../components/PlatformShell'
import { loadSession } from '../lib/auth'
import { fetchChildSummary, type ChildSummaryDto } from '../api/parent'
import { PACKAGE_LABELS } from '../api/subscriptions'

interface ChildState {
  childId: string
  loading: boolean
  error: string | null
  summary: ChildSummaryDto | null
}

function ChildCard({ state }: { state: ChildState }) {
  const { childId, loading, error, summary } = state
  return (
    <div className="kb-card" style={{ padding: 20, display: 'flex', flexDirection: 'column', gap: 16 }}>
      <header style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 8 }}>
        <h2 style={{ margin: 0, fontSize: 18, fontWeight: 800 }}>Ребёнок · {childId.slice(0, 8)}</h2>
        <Link to="/billing" className="kb-btn kb-btn--secondary" style={{ fontSize: 12, padding: '4px 12px' }}>
          Продлить пакет
        </Link>
      </header>

      {loading && <div style={{ color: 'var(--ink-soft)' }}>Загрузка…</div>}
      {error && <div style={{ color: '#dc2626', fontSize: 14 }}>{error}</div>}

      {summary && (
        <>
          <PackageSection summary={summary} />
          <ScheduleSection summary={summary} />
          <RecordingsSection summary={summary} />
        </>
      )}

      <NotificationsSection />
    </div>
  )
}

function PackageSection({ summary }: { summary: ChildSummaryDto }) {
  const sub = summary.subscription
  return (
    <section>
      <div className="eyebrow">Пакет</div>
      {sub ? (
        <div style={{ marginTop: 6, fontSize: 14 }}>
          <strong>{PACKAGE_LABELS[sub.plan]}</strong>
          <div style={{ marginTop: 4, color: 'var(--ink-soft)' }}>
            Осталось: {Math.max(0, sub.lessonsTotal - sub.lessonsUsed)} из {sub.lessonsTotal}
          </div>
          {sub.expiresAt && (
            <div style={{ color: 'var(--ink-soft)', fontSize: 12 }}>
              Действует до {new Date(sub.expiresAt).toLocaleDateString('ru-RU')}
            </div>
          )}
        </div>
      ) : (
        <div style={{ color: 'var(--ink-soft)', fontSize: 13, marginTop: 6 }}>Нет активного пакета</div>
      )}
    </section>
  )
}

function ScheduleSection({ summary }: { summary: ChildSummaryDto }) {
  const upcoming = summary.upcomingSlots.slice(0, 5)
  return (
    <section>
      <div className="eyebrow">Расписание</div>
      <div style={{ marginTop: 6, fontSize: 14 }}>
        {upcoming.length === 0 ? (
          <span style={{ color: 'var(--ink-soft)' }}>Нет запланированных занятий</span>
        ) : (
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            {upcoming.map((slot) => {
              const dt = new Date(slot.datetime)
              const href = `/room/slot-${slot.id}`
              return (
                <div key={slot.id} style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                  <span>
                    {dt.toLocaleString('ru-RU', { day: 'numeric', month: 'short', hour: '2-digit', minute: '2-digit' })}
                    <span style={{ color: 'var(--ink-soft)', marginLeft: 8 }}>({slot.durationMin} мин)</span>
                  </span>
                  <a
                    href={href}
                    target="_blank"
                    rel="noreferrer"
                    className="kb-btn"
                    style={{ fontSize: 11, padding: '3px 10px', textDecoration: 'none' }}
                  >
                    Перейти →
                  </a>
                </div>
              )
            })}
          </div>
        )}
      </div>
    </section>
  )
}

function RecordingsSection({ summary }: { summary: ChildSummaryDto }) {
  const reports = summary.recentReports
  const withVk = reports.filter((r) => r.vkRecordUrl)
  return (
    <section>
      <div className="eyebrow">Записи занятий</div>
      {reports.length === 0 ? (
        <div style={{ color: 'var(--ink-soft)', fontSize: 13, marginTop: 6 }}>Нет проведённых занятий</div>
      ) : (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 12, marginTop: 8 }}>
          <table style={{ width: '100%', borderCollapse: 'collapse', fontSize: 13 }}>
            <thead>
              <tr style={{ textAlign: 'left' }}>
                {['Дата', 'Статус', 'Оценка', 'Заметки'].map((h) => (
                  <th key={h} style={{ padding: '6px 8px', fontWeight: 700, fontSize: 12 }}>{h}</th>
                ))}
              </tr>
            </thead>
            <tbody>
              {reports.map((r) => (
                <tr key={r.id} style={{ borderTop: '1px solid var(--border, #e5e2f0)' }}>
                  <td style={{ padding: '6px 8px', whiteSpace: 'nowrap' }}>
                    {new Date(r.conductedAt).toLocaleDateString('ru-RU')}
                  </td>
                  <td style={{ padding: '6px 8px' }}>
                    {r.status === 'conducted' ? '✅ Проведён' : r.status === 'cancelled' ? '✖ Отменён' : '↺ Перенесён'}
                  </td>
                  <td style={{ padding: '6px 8px' }}>{r.grade ?? '—'}</td>
                  <td style={{ padding: '6px 8px', maxWidth: 240, overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                    {r.notes ?? '—'}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>

          {withVk.length > 0 && (
            <div style={{ display: 'grid', gap: 12, gridTemplateColumns: 'repeat(auto-fit, minmax(240px, 1fr))' }}>
              {withVk.slice(0, 3).map((r) => (
                <div key={r.id}>
                  <div style={{ fontSize: 12, color: 'var(--ink-soft)', marginBottom: 4 }}>
                    {new Date(r.conductedAt).toLocaleDateString('ru-RU')}
                  </div>
                  <div style={{ position: 'relative', paddingTop: '56.25%', borderRadius: 8, overflow: 'hidden', background: '#000' }}>
                    <iframe
                      src={r.vkRecordUrl ?? ''}
                      title={`Запись ${r.id}`}
                      allow="autoplay; encrypted-media; fullscreen"
                      allowFullScreen
                      style={{ position: 'absolute', inset: 0, width: '100%', height: '100%', border: 0 }}
                    />
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      )}
    </section>
  )
}

function NotificationsSection() {
  return (
    <section>
      <div className="eyebrow">Уведомления</div>
      <div style={{ marginTop: 6 }}>
        <Link to="/settings" className="kb-btn kb-btn--secondary" style={{ fontSize: 12, padding: '4px 12px' }}>
          Настройки уведомлений
        </Link>
      </div>
    </section>
  )
}

export default function Parent() {
  const session = loadSession()
  const [children, setChildren] = useState<ChildState[]>([])

  useEffect(() => {
    const ids = session?.linkedChildIds ?? []
    if (ids.length === 0) {
      setChildren([])
      return
    }
    setChildren(ids.map((id) => ({ childId: id, loading: true, error: null, summary: null })))
    ids.forEach((id) => {
      fetchChildSummary(id)
        .then((summary) => {
          setChildren((prev) => prev.map((c) => c.childId === id ? { ...c, loading: false, summary } : c))
        })
        .catch((e: unknown) => {
          const msg = e instanceof Error ? e.message : 'Ошибка загрузки'
          setChildren((prev) => prev.map((c) => c.childId === id ? { ...c, loading: false, error: msg } : c))
        })
    })
  }, [session?.linkedChildIds])

  return (
    <PlatformShell activeKey="parent">
      <div className="kb-cover kb-cover--violet">
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 36 }} aria-hidden>👨‍👩‍👧</span>
          <div>
            <div className="eyebrow" style={{ color: 'rgba(255,255,255,0.7)' }}>Родительский кабинет</div>
            <h1 className="h1" style={{ margin: 0, color: '#fff' }}>Прогресс детей</h1>
          </div>
        </div>
      </div>

      <div style={{ maxWidth: 960, margin: '0 auto', padding: '28px 16px', display: 'flex', flexDirection: 'column', gap: 20 }}>
        {!session && (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center' }}>
            Войдите в кабинет, чтобы увидеть прогресс детей.
            <div style={{ marginTop: 12 }}>
              <Link to="/login" className="kb-btn">Войти →</Link>
            </div>
          </div>
        )}

        {session && children.length === 0 && (
          <div className="kb-card" style={{ padding: 24, textAlign: 'center', color: 'var(--ink-soft)' }}>
            К аккаунту пока не привязан ни один ребёнок. Обратитесь к куратору.
          </div>
        )}

        {children.map((c) => (
          <ChildCard key={c.childId} state={c} />
        ))}
      </div>
    </PlatformShell>
  )
}
